// Generic API response wrapper — used across your entire application
interface ApiResponse<T> {
  data: T;
  error: string | null;
  status: 'success' | 'error' | 'loading';
  timestamp: Date;
}

// Course model with strict typing
interface Course {
  id: string;
  title: string;
  price: number;
  category: 'python' | 'devops' | 'react' | 'datasci';
  enrolledAt?: Date;  // optional — only present after enrollment
  isActive: boolean;
}

// TypeScript knows EXACTLY what this function returns
async function fetchCourse(id: string): Promise<ApiResponse<Course>> {
  const res = await fetch(`/api/courses/${id}`);
  return res.json();
}

// Usage — compiler catches every mistake
const result = await fetchCourse('py-001');
if (result.status === 'success') {
  console.log(result.data.title);       // ✅ TypeScript knows this exists
  console.log(result.data.price * 1.1); // ✅ number × number = valid
  console.log(result.data.unknown);     // ❌ Error at compile time — not runtime
  result.data.category = 'java';        // ❌ 'java' is not in the union type
}

// app/courses/page.tsx — Server Component
// Runs ONLY on server. Direct DB access. Zero JavaScript to browser.

import { db } from '@/lib/db';

// Server Action — replaces a POST API route
async function enrollInCourse(formData: FormData) {
  'use server'; // marks this function as a Server Action

  const courseId = formData.get('courseId') as string;
  const userId   = await getCurrentUserId(); // server-side auth

  await db.enrollment.create({
    data: { courseId, userId }
  });

  // revalidatePath('/courses'); // refresh this page's cache
}

export default async function CoursesPage() {
  // Direct DB query — this never ships to the browser
  const courses = await db.course.findMany({
    where: { isActive: true },
    include: { instructor: true },
    orderBy: { createdAt: 'desc' }
  });

  return (
    <main>
      {courses.map(course => (
        <div key={course.id}>
          <h2>{course.title}</h2>
          <p>By {course.instructor.name}</p>

          {/* Server Action — no API route, no fetch, no state */}
          <form action={enrollInCourse}>
            <input type="hidden" name="courseId" value={course.id} />
            <button type="submit">Enroll Now</button>
          </form>
        </div>
      ))}
    </main>
  );
}
